<template>
    <main>
        <div class="preloader" v-if="!countItems"><b-spinner variant="primary" type="grow" label="Spinning"></b-spinner></div>
        <div class="container">
            <div class="main-wrapper">
                <h1 class="catalog-title">
                    Коллекция №{{id}}
                    <span>{{title}}</span>
                </h1>
                <div class="catalog chess" v-if="countItems">
                    <a v-for="(item, index) in items" v-bind:key="item.id" v-bind:data-title="item.name" class="chess__item" @click="detail(item.id)">
                        <span class="chess__num">{{index+1}}</span>
                        <div class="chess__img" v-bind:style="{ backgroundImage: 'url(' + item.previewPicture + ')' }"></div> 
                        <p class="chess__discription">
                            {{item.name}}
                        </p>
                    </a>
                </div>
                <div class="catalog message-error" v-if="!countItems">Товары отсутствуют в данной коллекции</div>
            </div>
        </div>
    </main>
</template>
<script>
export default {
    name: 'catalogSection',
    data: function(){
        return {
            id: '',
            title: '',
            items: []  
        }
    },
    methods: {
        getCollectionInfo(){
            //console.log(this.$store.state);
        },
        detail(productId){
            this.$router.push('/catalog/'+this.id+'/'+productId);
        },
        getProducts(){
            let self = this;
            this.$store.dispatch('GET_PRODUCT_LIST', this.id)
            .then(response => {
                self.items = response.products;
                self.title = response.info.title;
                self.id = response.info.id;
             })
            .catch(err => console.log(err));
        }
    },
    computed: {
        countItems: function () {
			return Object.keys(this.items).length;
		},
    },
    mounted() {
        this.id = this.$route.params.id;
        
        this.getCollectionInfo();

        // загрузка товаров коллекции
        this.getProducts();
        
    }
}
</script>
<style lang="scss" scoped>
    .collections-container{
        width: 100%;
        .collections-link{
            display: flex;;
        }
    }
</style>